import { registerMvuSchema } from "https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js";

export const Schema = z.object({
  身份模式: z.enum(["原作", "共存"]).prefault("共存"),
  当前模式: z.enum(["剧情", "沙盒"]).prefault("剧情"),
  user: z.object({
    名字: z.string().prefault(""),
    身份: z.string().prefault(""),
    当前位置: z.string().prefault("阿尔泽纳尔 格纳库"),
  }).prefault({ 名字: "", 身份: "", 当前位置: "阿尔泽纳尔 格纳库" }),
  关系网: z.record(z.string().describe("角色名"), z.object({
    好感度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    信任度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    关系: z.string().prefault("陌生人"),
  })).prefault({}),
  剧情: z.object({
    当前卷: z.coerce.number().transform(v => _.clamp(v, 1, 25)).prefault(1),
    当前章节: z.string().prefault(""),
    章节内已完成事件: z.string().prefault(""),
    关键事件: z.string().prefault(""),
    模式: z.string().prefault("日常"),
    推进许可: z.boolean().prefault(false),
  }).prefault({ 当前卷: 1, 当前章节: "", 章节内已完成事件: "", 关键事件: "", 模式: "日常", 推进许可: false }),
  沙盒状态: z.object({
    当前时间: z.string().prefault("第1天·白天"),
    当前地点: z.string().prefault("阿尔泽纳尔"),
    当前节点: z.string().prefault(""),
    时间推进次数: z.coerce.number().prefault(0),
    关键事件触发记录: z.string().prefault(""),
  }).prefault({ 当前时间: "第1天·白天", 当前地点: "阿尔泽纳尔", 当前节点: "", 时间推进次数: 0, 关键事件触发记录: "" }),
});

;

// [CROSS ANGE] 开局切换剧情/沙盒
const STORY_NAMES=['[CROSS ANGE] 第'];
const SAND_NAMES=['沙盒'];
const SWIPE_MODES={0:'story',1:'story',2:'story',3:'sandbox',4:'sandbox',5:'sandbox'};
let currentSwipeIndex=-1,isInitialized=false,monitorInterval=null;
async function updateEntries(swipeIndex){
  const mode=SWIPE_MODES[swipeIndex.toString()];
  if(!mode)return;
  const isStory=mode==='story';
  const book=TavernHelper.getCurrentCharPrimaryLorebook();
  if(!book)return;
  try{
    const entries=await TavernHelper.getLorebookEntries(book);
    if(!entries)return;
    const mods=[];
    for(const e of entries){
      const c=e.comment||'';
      if(STORY_NAMES.some(function(n){return c.includes(n);})&&e.enabled!==isStory){mods.push({uid:e.uid,enabled:isStory});}
      if(SAND_NAMES.some(function(n){return c.includes(n);})&&e.enabled!==!isStory){mods.push({uid:e.uid,enabled:!isStory});}
    }
    if(mods.length>0){await TavernHelper.setLorebookEntries(book,mods);toastr.success((isStory?'剧情':'沙盒')+'模式 ('+mods.length+'条目)');}
  }catch(e){console.error(e);}
}
async function getSwipeIndex(){
  try{const msgs=await TavernHelper.getChatMessages(0,{include_swipe:true});return(msgs&&msgs[0])?(msgs[0].swipe_id||0):-1;}catch(e){return -1;}
}
async function monitor(){
  try{const idx=await getSwipeIndex();if(idx>=0&&idx!==currentSwipeIndex){if(isInitialized)toastr.info('开场白已切换');currentSwipeIndex=idx;await updateEntries(idx);}}catch(e){}
}
async function onSwiped(id){if(id===0)await monitor();}
function startMonitor(){if(monitorInterval)clearInterval(monitorInterval);monitorInterval=setInterval(monitor,500);}
const safeSwiped=TavernHelper.errorCatched(onSwiped);
function onScriptLoad(){
  toastr.success('[CROSS ANGE] 开局切换已激活');
  if(typeof eventOn==='function'&&tavern_events?.MESSAGE_SWIPED){eventOn(tavern_events.MESSAGE_SWIPED,async function(id){await safeSwiped(id);});}
  startMonitor();
  setTimeout(async function(){currentSwipeIndex=await getSwipeIndex();isInitialized=true;},1000);
}
function onScriptUnload(){if(monitorInterval){clearInterval(monitorInterval);monitorInterval=null;}currentSwipeIndex=-1;isInitialized=false;}
jQuery(function(){onScriptLoad();});
jQuery(window).on('pagehide',function(){onScriptUnload();});
